import{_ as e,c as i,o as t,ae as o}from"./chunks/framework.B7Y1jjX-.js";const p=JSON.parse('{"title":"字节跳动-字节云-豆包前端实习-一面","description":"","frontmatter":{},"headers":[],"relativePath":"notes/前端/面试/2字节跳动-豆包前端实习.md","filePath":"notes/前端/面试/2字节跳动-豆包前端实习.md"}'),a={name:"notes/前端/面试/2字节跳动-豆包前端实习.md"};function r(d,l,n,s,h,c){return t(),i("div",null,[...l[0]||(l[0]=[o('<h1 id="字节跳动-字节云-豆包前端实习-一面" tabindex="-1">字节跳动-字节云-豆包前端实习-一面 <a class="header-anchor" href="#字节跳动-字节云-豆包前端实习-一面" aria-label="Permalink to &quot;字节跳动-字节云-豆包前端实习-一面&quot;">​</a></h1><p>时间：一面11.24.25</p><h2 id="_1-面试流程" tabindex="-1">1 面试流程 <a class="header-anchor" href="#_1-面试流程" aria-label="Permalink to &quot;1 面试流程&quot;">​</a></h2><ol><li>自我介绍</li><li>提问</li><li>编代码</li><li>向面试官提问</li></ol><h2 id="_2-面试内容-提问、代码与反向提问" tabindex="-1">2 面试内容（提问、代码与反向提问） <a class="header-anchor" href="#_2-面试内容-提问、代码与反向提问" aria-label="Permalink to &quot;2 面试内容（提问、代码与反向提问）&quot;">​</a></h2><h3 id="提问" tabindex="-1">提问 <a class="header-anchor" href="#提问" aria-label="Permalink to &quot;提问&quot;">​</a></h3><ol><li>绝对定位和相对定位</li><li>弹性布局</li><li>flex：1是什么意思</li><li>原始值的种类（7种）</li><li>GET与POST的区别</li><li>http协议的其他请求方法</li><li>浏览器的同源策略</li><li>反向代理是什么</li><li>cookie与session</li><li>git中的rebase和merge</li><li>移动端优先的设计理念</li><li>为什么选择Vue3作为技术栈</li><li>为什么要节流，以及其定义</li></ol><h3 id="代码" tabindex="-1">代码 <a class="header-anchor" href="#代码" aria-label="Permalink to &quot;代码&quot;">​</a></h3><p>涉及测试用例的编写，以及怎么保证函数能够通过测试</p><ol><li>节流函数</li><li>冒泡排序原理及代码 这部分有一个问题：一个排序函数要输入一个值，如果输入的不是一个数组，那我把它判断出来之后该怎么处理，我应该返回什么，还是应该报错？</li><li>数组去重</li></ol><h3 id="提问-1" tabindex="-1">提问 <a class="header-anchor" href="#提问-1" aria-label="Permalink to &quot;提问&quot;">​</a></h3><ol><li>团队的技术选型的考量</li><li>AI与低代码平台对前端的影响</li><li>团队对新人与实习生的帮助</li></ol><h2 id="_3-复盘反思" tabindex="-1">3 复盘反思 <a class="header-anchor" href="#_3-复盘反思" aria-label="Permalink to &quot;3 复盘反思&quot;">​</a></h2><p>首先基础的概念我记得不太清了，针对弹性布局和相对定位这些基础的内容我回答的不够完美。其次是算法设计与一些API的编写，我几乎都忘干净了，尤其是针对节流和防抖的内容。git也是。</p><p>据我分析，这个团队的技术栈应该不会包括Vue生态，而是React，因为他表示React的上限更高，对于Vue相关的内容的提问是没有的，如果我有React生态的技术栈，那就该拷打我的这部分了。</p><p>全部集中于基础，内容较学院派。要针对简历上的内容进行针对性的复习。对于个人经历部分，我的自我介绍应该是有些简单了，但是面试官也没问，应该也就是不重要。</p><p>整体上来讲，能答的都答了，除了表述的不够严谨，本质上也都是回答出来了。我个人认为还算是一次可以满分10分，打6.5分的这么一次面试，勉勉强合格？</p><h2 id="_4-参考答案" tabindex="-1">4 参考答案 <a class="header-anchor" href="#_4-参考答案" aria-label="Permalink to &quot;4 参考答案&quot;">​</a></h2><h3 id="_1-绝对定位和相对定位" tabindex="-1">1. 绝对定位和相对定位 <a class="header-anchor" href="#_1-绝对定位和相对定位" aria-label="Permalink to &quot;1. 绝对定位和相对定位&quot;">​</a></h3><p><strong>相对定位（relative）</strong>：</p><ul><li>元素相对于自身正常位置进行定位</li><li>不会脱离文档流，原位置仍保留</li><li>通过 top、right、bottom、left 属性调整位置</li></ul><p><strong>绝对定位（absolute）</strong>：</p><ul><li>元素相对于最近的已定位祖先元素进行定位</li><li>脱离文档流，不占据原空间</li><li>如果没有已定位祖先，则相对于初始包含块（通常是视口）</li></ul><h3 id="_2-弹性布局" tabindex="-1">2. 弹性布局 <a class="header-anchor" href="#_2-弹性布局" aria-label="Permalink to &quot;2. 弹性布局&quot;">​</a></h3><p>弹性布局（Flexbox）是一维布局模型，用于在容器内高效分配空间和对齐项目。</p><p>主要特性：</p><ul><li><code>display: flex</code> 创建弹性容器</li><li>主轴（main axis）和交叉轴（cross axis）</li><li>灵活的项目大小调整和对齐控制</li><li>响应式设计友好</li></ul><h3 id="_3-flex-1-是什么意思" tabindex="-1">3. flex: 1 是什么意思 <a class="header-anchor" href="#_3-flex-1-是什么意思" aria-label="Permalink to &quot;3. flex: 1 是什么意思&quot;">​</a></h3><p><code>flex: 1</code> 是 <code>flex-grow: 1</code>、<code>flex-shrink: 1</code>、<code>flex-basis: 0%</code> 的简写：</p><ul><li><code>flex-grow: 1</code>：项目可以伸展占用剩余空间</li><li><code>flex-shrink: 1</code>：项目可以收缩防止溢出</li><li><code>flex-basis: 0%</code>：项目在分配多余空间前的初始大小</li></ul><h3 id="_4-原始值的种类-7种" tabindex="-1">4. 原始值的种类（7种） <a class="header-anchor" href="#_4-原始值的种类-7种" aria-label="Permalink to &quot;4. 原始值的种类（7种）&quot;">​</a></h3><p>JavaScript 的 7 种原始数据类型：</p><ol><li><code>undefined</code></li><li><code>null</code></li><li><code>boolean</code></li><li><code>number</code></li><li><code>string</code></li><li><code>symbol</code>（ES6）</li><li><code>bigint</code>（ES2020）</li></ol><h3 id="_5-get-与-post-的区别" tabindex="-1">5. GET 与 POST 的区别 <a class="header-anchor" href="#_5-get-与-post-的区别" aria-label="Permalink to &quot;5. GET 与 POST 的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>GET</th><th>POST</th></tr></thead><tbody><tr><td>安全性</td><td>参数在URL中，不安全</td><td>参数在请求体中，相对安全</td></tr><tr><td>数据长度</td><td>有限制（URL长度限制）</td><td>无限制</td></tr><tr><td>缓存</td><td>可被缓存</td><td>不会被缓存</td></tr><tr><td>幂等性</td><td>幂等（多次请求结果相同）</td><td>非幂等</td></tr><tr><td>用途</td><td>获取数据</td><td>提交数据</td></tr></tbody></table><h3 id="_6-http-协议的其他请求方法" tabindex="-1">6. HTTP 协议的其他请求方法 <a class="header-anchor" href="#_6-http-协议的其他请求方法" aria-label="Permalink to &quot;6. HTTP 协议的其他请求方法&quot;">​</a></h3><ul><li><strong>PUT</strong>：替换目标资源</li><li><strong>DELETE</strong>：删除资源</li><li><strong>HEAD</strong>：获取响应头，不返回响应体</li><li><strong>OPTIONS</strong>：描述目标资源的通信选项</li><li><strong>PATCH</strong>：对资源部分修改</li><li><strong>TRACE</strong>：回显服务器收到的请求</li></ul><h3 id="_7-浏览器的同源策略" tabindex="-1">7. 浏览器的同源策略 <a class="header-anchor" href="#_7-浏览器的同源策略" aria-label="Permalink to &quot;7. 浏览器的同源策略&quot;">​</a></h3><p>同源策略限制不同源的文档或脚本之间的交互。同源要求：</p><ul><li>协议相同</li><li>域名相同</li><li>端口相同</li></ul><p>跨域解决方案：CORS、JSONP、代理服务器等。</p><h3 id="_8-cookie-与-session" tabindex="-1">8. Cookie 与 Session <a class="header-anchor" href="#_8-cookie-与-session" aria-label="Permalink to &quot;8. Cookie 与 Session&quot;">​</a></h3><p><strong>Cookie</strong>：</p><ul><li>存储在客户端</li><li>大小限制约4KB</li><li>每次请求自动携带</li><li>安全性较低</li></ul><p><strong>Session</strong>：</p><ul><li>存储在服务器端</li><li>无大小限制</li><li>通过Session ID识别</li><li>安全性较高</li></ul><h3 id="_9-git-中的-rebase-和-merge" tabindex="-1">9. Git 中的 rebase 和 merge <a class="header-anchor" href="#_9-git-中的-rebase-和-merge" aria-label="Permalink to &quot;9. Git 中的 rebase 和 merge&quot;">​</a></h3><p><strong>merge</strong>：</p><ul><li>保留分支历史，创建新的合并提交</li><li>历史记录更完整但可能复杂 ![[Pasted image 20251125121812.png]] <strong>rebase</strong>：</li><li>将分支基础重置到另一分支</li><li>历史记录更线性整洁</li><li>会重写提交历史 ![[Pasted image 20251125121900.png]]</li></ul><h3 id="_10-移动端优先的设计理念" tabindex="-1">10. 移动端优先的设计理念 <a class="header-anchor" href="#_10-移动端优先的设计理念" aria-label="Permalink to &quot;10. 移动端优先的设计理念&quot;">​</a></h3><p>移动端优先（Mobile First）设计理念：</p><ol><li>先为移动设备设计，再扩展到桌面端</li><li>关注核心内容和功能</li><li>考虑移动设备性能限制</li><li>渐进增强策略</li></ol><h3 id="_11-为什么选择-vue3-作为技术栈" tabindex="-1">11. 为什么选择 Vue3 作为技术栈 <a class="header-anchor" href="#_11-为什么选择-vue3-作为技术栈" aria-label="Permalink to &quot;11. 为什么选择 Vue3 作为技术栈&quot;">​</a></h3><p>Vue3 的优势：</p><ul><li><strong>更好的性能</strong>：使用Proxy实现响应式，优化虚拟DOM</li><li><strong>组合式API</strong>：更好的逻辑复用和代码组织</li><li><strong>更好的TypeScript支持</strong></li><li><strong>更小的包体积</strong>：Tree-shaking优化</li><li><strong>新的特性</strong>：Teleport、Suspense等</li></ul><h3 id="_12-为什么要节流-以及其定义" tabindex="-1">12. 为什么要节流，以及其定义 <a class="header-anchor" href="#_12-为什么要节流-以及其定义" aria-label="Permalink to &quot;12. 为什么要节流，以及其定义&quot;">​</a></h3><p><strong>为什么需要节流</strong>：</p><ul><li>防止高频事件（如scroll、resize、input）过度触发</li><li>减少不必要的函数执行，提升性能</li><li>避免浏览器卡顿</li></ul><p><strong>节流定义</strong>： 在规定时间内，函数只能执行一次。如果在此期间再次触发，会被忽略。</p><h1 id="字节跳动-字节云-豆包前端实习-二面" tabindex="-1">字节跳动-字节云-豆包前端实习-二面 <a class="header-anchor" href="#字节跳动-字节云-豆包前端实习-二面" aria-label="Permalink to &quot;字节跳动-字节云-豆包前端实习-二面&quot;">​</a></h1><p>时间：11/27/25 时长：1h</p><h2 id="_1-内容" tabindex="-1">1 内容 <a class="header-anchor" href="#_1-内容" aria-label="Permalink to &quot;1 内容&quot;">​</a></h2><ul><li>自我介绍</li><li>提问</li><li>代码</li><li>反问</li></ul><h2 id="_2-提问-32个问题" tabindex="-1">2 提问（32个问题） <a class="header-anchor" href="#_2-提问-32个问题" aria-label="Permalink to &quot;2 提问（32个问题）&quot;">​</a></h2><ul><li><p>你的开源项目是什么呢</p></li><li><p>你什么时候开始接触前端</p></li><li><p>之前有过实习呢</p></li><li><p>学前端你都做了什么呢</p></li><li><p>在github上的具体项目贡献</p></li><li><p>项目的来源？</p></li><li><p>修了哪些Bug呢？</p></li><li><p>pr与issue的个数</p></li><li><p>介绍自己的一个项目，具体做了什么呢，怎么实现的呢</p></li><li><p>什么是SPA？</p></li><li><p>你的前端路由是怎么设计的呢？</p></li><li><p>一刻的技术栈？</p></li><li><p>去看一刻有多少个路由？</p></li><li><p>看看localstorage的内容</p></li><li><p>介绍深岩智测的项目</p></li><li><p>深岩的数据是哪里来的</p></li><li><p>用了哪些技术栈</p></li><li><p>有多少个图表，什么样的？</p></li><li><p>这些图的算法</p></li><li><p>你掌握的前端知识点有哪些？</p></li><li><p>浏览器渲染原理</p></li><li><p>浏览器有多少线程呢</p></li><li><p>一个页面会有多少线程呢？</p></li><li><p>有没有事件线程呢，点击鼠标和键盘事件</p></li><li><p>你了解事件循环机制吗</p></li><li><p>微任务与宏任务有什么区别呢</p></li><li><p>平时在用什么AI呢，学习中，开发中有没有用到呢</p></li><li><p>对于使用AI开发过程中遇到的问题</p></li><li><p>你要怎么向AI沟通与提问他生成的代码才会更好</p></li><li><p>你了解哪些AI了解呢</p></li><li><p>在和AI对话的过程中，AI发生了错误，但你“越聊越错”，对于这种现象是什么原因呢</p></li><li><p>为什么无法进行纠错，“越聊越正确”呢？为什么越聊幻觉越大呢</p></li></ul><h2 id="_3-代码" tabindex="-1">3 代码 <a class="header-anchor" href="#_3-代码" aria-label="Permalink to &quot;3 代码&quot;">​</a></h2><ul><li>防抖节流</li><li>针对DOM树的diff算法</li></ul><h2 id="_4-参考答案-1" tabindex="-1">4 参考答案 <a class="header-anchor" href="#_4-参考答案-1" aria-label="Permalink to &quot;4 参考答案&quot;">​</a></h2><p>以下是针对每个问题的 <strong>细致学习版答案</strong>，侧重原理拆解、逻辑推导和实际场景，帮你彻底理解核心知识点，而非单纯记结论：</p><h3 id="一、浏览器渲染原理-核心流程-关键概念" tabindex="-1">一、浏览器渲染原理（核心流程+关键概念） <a class="header-anchor" href="#一、浏览器渲染原理-核心流程-关键概念" aria-label="Permalink to &quot;一、浏览器渲染原理（核心流程+关键概念）&quot;">​</a></h3><p>浏览器的核心目标是把 HTML/CSS/JS 转化为用户能看到的页面，整个过程分 <strong>5个核心步骤</strong>，且是“逐步解析+增量渲染”（不是等所有资源加载完才开始）：</p><h4 id="_1-解析-html-→-生成-dom-树-document-object-model" tabindex="-1">1. 解析 HTML → 生成 DOM 树（Document Object Model） <a class="header-anchor" href="#_1-解析-html-→-生成-dom-树-document-object-model" aria-label="Permalink to &quot;1. 解析 HTML → 生成 DOM 树（Document Object Model）&quot;">​</a></h4><ul><li>原理：浏览器按 <strong>从上到下的顺序</strong> 读取 HTML 字符流，通过“HTML 解析器”将标签、属性、文本等转化为 DOM 节点（树状结构，根节点是 <code>document</code>）。</li><li>关键细节： <ul><li>遇到 <code>&lt;link rel=&quot;stylesheet&quot;&gt;</code>：会暂停 HTML 解析，先加载 CSS 并解析（因为 CSS 会影响 DOM 的样式，避免后续重复渲染）；</li><li>遇到 <code>&lt;script&gt;</code>：会 <strong>阻塞 HTML 解析和 DOM 生成</strong>（因为 JS 可能修改 DOM/CSS，浏览器无法预测，只能先执行 JS）；</li><li>解决阻塞：<code>defer</code>（延迟执行，不阻塞 HTML 解析，DOM 加载完后执行）、<code>async</code>（异步加载，加载完立即执行，可能打乱 JS 顺序）。</li></ul></li></ul><h4 id="_2-解析-css-→-生成-cssom-树-css-object-model" tabindex="-1">2. 解析 CSS → 生成 CSSOM 树（CSS Object Model） <a class="header-anchor" href="#_2-解析-css-→-生成-cssom-树-css-object-model" aria-label="Permalink to &quot;2. 解析 CSS → 生成 CSSOM 树（CSS Object Model）&quot;">​</a></h4><ul><li>原理：CSS 解析器将 CSS 规则（内联、内部、外部）转化为树状结构，每个节点存储对应元素的样式属性（如 <code>color</code>、<code>font-size</code>）。</li><li>关键：CSS 支持“继承”和“层叠”，CSSOM 会计算每个元素的 <strong>最终样式</strong>（比如子元素继承父元素的 <code>font-family</code>，同名规则按优先级覆盖）。</li></ul><h4 id="_3-合并-dom-cssom-→-生成渲染树-render-tree" tabindex="-1">3. 合并 DOM + CSSOM → 生成渲染树（Render Tree） <a class="header-anchor" href="#_3-合并-dom-cssom-→-生成渲染树-render-tree" aria-label="Permalink to &quot;3. 合并 DOM + CSSOM → 生成渲染树（Render Tree）&quot;">​</a></h4><ul><li>原理：筛选出“可见元素”，并将 DOM 节点与对应的 CSSOM 样式绑定。</li><li>过滤规则： <ul><li>隐藏元素（<code>display: none</code>）不会进入渲染树（<code>visibility: hidden</code> 会进入，因为只是不可见，仍占空间）；</li><li><code>&lt;head&gt;</code> 标签及内部元素（除非手动设置可见）会被过滤。</li></ul></li><li>核心：渲染树只包含“要显示的元素+其样式”，是后续布局和绘制的基础。</li></ul><h4 id="_4-布局-layout-reflow-→-计算元素位置和大小" tabindex="-1">4. 布局（Layout/Reflow）→ 计算元素位置和大小 <a class="header-anchor" href="#_4-布局-layout-reflow-→-计算元素位置和大小" aria-label="Permalink to &quot;4. 布局（Layout/Reflow）→ 计算元素位置和大小&quot;">​</a></h4><ul><li>原理：遍历渲染树，计算每个节点的 <strong>几何信息</strong>（坐标 <code>x/y</code>、宽高 <code>width/height</code>），最终输出“布局树”（Layout Tree）。</li><li>触发场景： <ul><li>初始渲染（必触发）；</li><li>DOM 结构修改（如增删节点、修改 <code>innerHTML</code>）；</li><li>CSS 样式修改（如 <code>width</code>、<code>margin</code>、<code>display</code>）；</li><li>窗口大小变化（<code>resize</code> 事件）；</li><li>获取某些属性（如 <code>offsetWidth</code>、<code>scrollTop</code>，会强制刷新布局）。</li></ul></li><li>性能影响：布局是“递归过程”（父元素位置变了，子元素也要重新计算），成本较高，应尽量避免频繁触发。</li></ul><h4 id="_5-绘制-painting-→-将布局树转化为像素" tabindex="-1">5. 绘制（Painting）→ 将布局树转化为像素 <a class="header-anchor" href="#_5-绘制-painting-→-将布局树转化为像素" aria-label="Permalink to &quot;5. 绘制（Painting）→ 将布局树转化为像素&quot;">​</a></h4><ul><li>原理：浏览器的“绘制引擎”按布局树的几何信息，将元素的样式（颜色、背景、边框等）绘制到屏幕的“像素缓冲区”。</li><li>触发场景：布局后必触发；仅修改“不影响布局”的样式（如 <code>color</code>、<code>background-color</code>、<code>box-shadow</code>）时，会直接触发绘制（不触发布局）。</li></ul><h4 id="_6-合成-compositing-→-合并图层并显示" tabindex="-1">6. 合成（Compositing）→ 合并图层并显示 <a class="header-anchor" href="#_6-合成-compositing-→-合并图层并显示" aria-label="Permalink to &quot;6. 合成（Compositing）→ 合并图层并显示&quot;">​</a></h4><ul><li>原理：浏览器会将绘制后的内容按“图层”拆分（比如视频、动画、<code>position: fixed</code> 元素会单独成层），然后通过 GPU 合并所有图层，最终显示到屏幕上。</li><li>核心优势：图层独立绘制，修改某一层时不会影响其他层（比如动画用 <code>transform</code> 而非 <code>top</code>，只会触发合成，不触发布局和绘制，性能极高）。</li></ul><h4 id="总结关键链路" tabindex="-1">总结关键链路： <a class="header-anchor" href="#总结关键链路" aria-label="Permalink to &quot;总结关键链路：&quot;">​</a></h4><p>HTML → DOM → CSSOM → 渲染树 → 布局 → 绘制 → 合成 → 屏幕显示<br> （性能优化核心：减少布局和绘制的触发次数，尽量只触发合成）</p><h3 id="二、浏览器有多少线程-多进程-多线程架构" tabindex="-1">二、浏览器有多少线程？（多进程+多线程架构） <a class="header-anchor" href="#二、浏览器有多少线程-多进程-多线程架构" aria-label="Permalink to &quot;二、浏览器有多少线程？（多进程+多线程架构）&quot;">​</a></h3><p>首先明确：<strong>浏览器是“多进程”架构</strong>（每个进程有独立内存空间，互不干扰），而每个进程内部包含多个“线程”（共享进程内存，协同工作）。</p><h4 id="_1-浏览器的核心进程-4个核心进程" tabindex="-1">1. 浏览器的核心进程（4个核心进程） <a class="header-anchor" href="#_1-浏览器的核心进程-4个核心进程" aria-label="Permalink to &quot;1. 浏览器的核心进程（4个核心进程）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>进程名称</th><th>作用</th></tr></thead><tbody><tr><td>浏览器进程（主进程）</td><td>管理窗口、用户交互（如地址栏输入）、网络请求调度、进程间通信（IPC）。</td></tr><tr><td>渲染进程（标签页进程）</td><td>核心进程！负责页面渲染（HTML/CSS/JS 解析）、执行 JS、处理 DOM 等（每个标签页默认一个，同域名可能合并）。</td></tr><tr><td>GPU 进程</td><td>处理 GPU 加速任务（如 3D 渲染、图层合成、视频播放），避免阻塞渲染进程。</td></tr><tr><td>插件进程</td><td>运行浏览器插件（如 Flash、Chrome 插件），独立进程防止插件崩溃影响其他进程。</td></tr></tbody></table><h4 id="_2-渲染进程内的核心线程-重点-前端相关" tabindex="-1">2. 渲染进程内的核心线程（重点！前端相关） <a class="header-anchor" href="#_2-渲染进程内的核心线程-重点-前端相关" aria-label="Permalink to &quot;2. 渲染进程内的核心线程（重点！前端相关）&quot;">​</a></h4><p>渲染进程是前端最关注的，内部包含 <strong>5个核心线程</strong>（各司其职，协同工作）：</p><table tabindex="0"><thead><tr><th>线程名称</th><th>作用</th><th>关键特性</th></tr></thead><tbody><tr><td>JS 引擎线程（V8 线程）</td><td>执行 JS 代码（同步代码）、管理调用栈。</td><td>单线程！同一时间只能执行一个任务（避免 DOM 冲突），与 GUI 渲染线程互斥。</td></tr><tr><td>GUI 渲染线程</td><td>执行渲染流程（解析 HTML/CSS、生成渲染树、布局、绘制）。</td><td>与 JS 引擎线程互斥：JS 执行时 GUI 会暂停，GUI 执行时 JS 会暂停（避免样式和 DOM 不一致）。</td></tr><tr><td>事件触发线程</td><td>管理“事件队列”（如点击、键盘、定时器、AJAX 回调）。</td><td>独立于 JS 引擎线程，当事件触发时，将回调函数放入事件队列，等待 JS 引擎空闲时执行。</td></tr><tr><td>定时器线程（setTimeout/setInterval）</td><td>管理定时器的计时和触发。</td><td>独立于 JS 引擎线程（避免 JS 阻塞导致计时不准），计时结束后将回调放入事件队列。</td></tr><tr><td>HTTP 请求线程</td><td>处理 AJAX/fetch 网络请求。</td><td>独立线程，可同时发起多个请求（浏览器限制同域名最大并发数，一般 6 个），请求完成后将回调放入事件队列。</td></tr><tr><td>这与之前的学习说法有不同</td><td></td><td></td></tr><tr><td><strong>两种说法不一致的核心原因是对渲染进程主线程角色的理解不同</strong>：</td><td></td><td></td></tr></tbody></table><ul><li>正确模型中，<strong>渲染进程有一个核心主线程</strong>，它既是 &quot;JS 引擎线程&quot; 也是 &quot;GUI 渲染线程&quot;，二者<strong>互斥运行</strong>而非并行</li><li>渲染流水线还包括<strong>合成线程</strong>和<strong>栅格线程</strong>等辅助线程，负责渲染的后期阶段，与主线程协同工作</li></ul><p><strong>你的模型</strong>虽有简化，但对理解 JS 单线程特性和事件循环机制有帮助；<strong>正确模型</strong>则更准确反映现代浏览器的实际架构，对性能优化和问题排查更有指导意义。</p><p>若需深入理解，建议重点掌握：<strong>主线程的核心地位</strong>、<strong>JS 与渲染互斥原则</strong>、<strong>合成线程与主线程的协作流程</strong>。</p><h4 id="总结" tabindex="-1">总结： <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结：&quot;">​</a></h4><ul><li>浏览器整体：进程数 ≈ 标签页数（同域名合并）+ 核心进程（主进程、GPU、插件）；</li><li>单个渲染进程：固定包含 5 个核心线程（JS 引擎、GUI、事件触发、定时器、HTTP 请求），可额外通过 <code>Web Worker</code> 创建新线程（见下一个问题）。</li></ul><h3 id="三、一个页面会有多少线程" tabindex="-1">三、一个页面会有多少线程？ <a class="header-anchor" href="#三、一个页面会有多少线程" aria-label="Permalink to &quot;三、一个页面会有多少线程？&quot;">​</a></h3><p>一个页面（对应一个渲染进程）的线程数 = <strong>核心线程数 + 自定义线程数</strong>：</p><h4 id="_1-基础线程-必存在-5-个" tabindex="-1">1. 基础线程（必存在）：5 个 <a class="header-anchor" href="#_1-基础线程-必存在-5-个" aria-label="Permalink to &quot;1. 基础线程（必存在）：5 个&quot;">​</a></h4><p>即渲染进程内的核心线程（JS 引擎、GUI、事件触发、定时器、HTTP 请求），无论页面是否复杂，这 5 个线程都存在。</p><h4 id="_2-自定义线程-可选-web-worker-线程" tabindex="-1">2. 自定义线程（可选）：Web Worker 线程 <a class="header-anchor" href="#_2-自定义线程-可选-web-worker-线程" aria-label="Permalink to &quot;2. 自定义线程（可选）：Web Worker 线程&quot;">​</a></h4><ul><li>原理：JS 引擎是单线程，但浏览器允许通过 <code>new Worker()</code> 创建 <strong>后台线程</strong>（Web Worker），用于执行耗时操作（如大数据计算、复杂逻辑处理）。</li><li>关键限制： <ul><li>不能操作 DOM/CSS（无 <code>document</code>、<code>window</code> 对象），只能通过 <code>postMessage</code> 与主线程通信；</li><li>不能跨域加载脚本（Worker 脚本必须和页面同域名）；</li><li>数量限制：浏览器对单个页面的 Worker 线程数有上限（一般 20-50 个，避免占用过多资源）。</li></ul></li></ul><h4 id="_3-特殊线程-按需创建" tabindex="-1">3. 特殊线程（按需创建）： <a class="header-anchor" href="#_3-特殊线程-按需创建" aria-label="Permalink to &quot;3. 特殊线程（按需创建）：&quot;">​</a></h4><ul><li>Service Worker 线程：用于离线缓存、推送通知，属于独立于渲染进程的线程（关联页面，但在后台运行）；</li><li>Shared Worker 线程：多个同域名页面可共享的 Worker 线程（跨页面通信）。</li></ul><h3 id="四、有没有事件线程-点击-键盘事件的处理流程" tabindex="-1">四、有没有事件线程？点击/键盘事件的处理流程 <a class="header-anchor" href="#四、有没有事件线程-点击-键盘事件的处理流程" aria-label="Permalink to &quot;四、有没有事件线程？点击/键盘事件的处理流程&quot;">​</a></h3><p>不是哥们，到底有没有啊，dp说没有，豆包说有</p><h4 id="_1-结论-有-即渲染进程内的「事件触发线程」" tabindex="-1">1. 结论：有！即渲染进程内的「事件触发线程」 <a class="header-anchor" href="#_1-结论-有-即渲染进程内的「事件触发线程」" aria-label="Permalink to &quot;1. 结论：有！即渲染进程内的「事件触发线程」&quot;">​</a></h4><p>事件触发线程是独立于 JS 引擎的核心线程，专门负责管理所有“异步事件”的回调函数，包括：</p><ul><li>DOM 事件（点击、键盘、鼠标移动、滚动等）；</li><li>定时器事件（<code>setTimeout</code> 回调）；</li><li>网络事件（AJAX/fetch 回调）；</li><li>其他事件（如 <code>Promise</code> 状态变更、<code>MessageEvent</code>）。</li></ul><h4 id="_2-点击-键盘事件的完整处理流程-结合事件循环" tabindex="-1">2. 点击/键盘事件的完整处理流程（结合事件循环） <a class="header-anchor" href="#_2-点击-键盘事件的完整处理流程-结合事件循环" aria-label="Permalink to &quot;2. 点击/键盘事件的完整处理流程（结合事件循环）&quot;">​</a></h4><p>以“点击按钮”为例，拆解从触发到回调执行的全链路：</p><ol><li><strong>事件触发</strong>：用户点击按钮，浏览器的“输入设备驱动”捕获到点击事件，传递给浏览器主进程；</li><li><strong>事件分发</strong>：主进程通过 IPC 通信，将事件传递给当前页面的渲染进程；</li><li><strong>事件冒泡/捕获</strong>：渲染进程的 DOM 模块先执行事件捕获（从 <code>document</code> 向下到目标元素），再执行目标阶段，最后执行事件冒泡（从目标元素向上到 <code>document</code>）；</li><li><strong>回调入队</strong>：事件触发线程找到该事件绑定的回调函数（如 <code>btn.onclick = () =&gt; {}</code>），将其放入「事件队列」（宏任务队列）；</li><li><strong>等待执行</strong>：JS 引擎线程先执行完当前调用栈中的同步代码，空闲后从事件队列中取出回调函数，放入调用栈执行。</li></ol><h4 id="关键细节" tabindex="-1">关键细节： <a class="header-anchor" href="#关键细节" aria-label="Permalink to &quot;关键细节：&quot;">​</a></h4><ul><li>事件回调的执行时机：必须等 JS 引擎线程空闲（同步代码执行完），所以如果同步代码耗时过长，事件回调会被阻塞（比如点击按钮后，页面卡住几秒才响应，就是因为主线程被同步代码占用）；</li><li>事件委托的原理：利用事件冒泡，将子元素的事件绑定到父元素（如 <code>ul</code> 绑定点击事件，处理所有 <code>li</code> 的点击），本质是事件触发线程在冒泡阶段找到父元素的回调函数。</li></ul><h3 id="五、事件循环机制-event-loop-js-单线程的异步解决方案" tabindex="-1">五、事件循环机制（Event Loop）：JS 单线程的异步解决方案 <a class="header-anchor" href="#五、事件循环机制-event-loop-js-单线程的异步解决方案" aria-label="Permalink to &quot;五、事件循环机制（Event Loop）：JS 单线程的异步解决方案&quot;">​</a></h3><h4 id="_1-核心前提-js-为什么是单线程" tabindex="-1">1. 核心前提：JS 为什么是单线程？ <a class="header-anchor" href="#_1-核心前提-js-为什么是单线程" aria-label="Permalink to &quot;1. 核心前提：JS 为什么是单线程？&quot;">​</a></h4><ul><li>原因：避免 DOM 冲突（比如一个线程修改 DOM，另一个线程删除 DOM，会导致页面混乱）；</li><li>问题：单线程如果遇到耗时操作（如网络请求、定时器），会阻塞后续代码执行（页面卡住）；</li><li>解决方案：<strong>异步任务 + 事件循环</strong>（将耗时操作交给其他线程处理，主线程继续执行同步代码，后续再回调）。</li></ul><h4 id="_2-事件循环的核心概念" tabindex="-1">2. 事件循环的核心概念 <a class="header-anchor" href="#_2-事件循环的核心概念" aria-label="Permalink to &quot;2. 事件循环的核心概念&quot;">​</a></h4><ul><li>同步任务：立即执行的代码（如 <code>let a = 1</code>、<code>fn()</code>），直接进入「调用栈」执行；</li><li>异步任务：不立即执行的代码（如 <code>setTimeout</code>、<code>Promise.then</code>、AJAX），分为两类： <ul><li>宏任务（MacroTask）：由浏览器/宿主环境触发（如 <code>script</code> 整体、<code>setTimeout</code>、<code>setInterval</code>、DOM 事件、AJAX 回调、<code>requestAnimationFrame</code>）；</li><li>微任务（MicroTask）：由 JS 引擎自身触发（如 <code>Promise.then/catch/finally</code>、<code>MutationObserver</code>、<code>queueMicrotask</code>）；</li></ul></li><li>任务队列：存储异步任务的回调函数，分为「宏任务队列」（多个）和「微任务队列」（一个）。</li></ul><h4 id="_3-浏览器环境下的事件循环流程-重点" tabindex="-1">3. 浏览器环境下的事件循环流程（重点！） <a class="header-anchor" href="#_3-浏览器环境下的事件循环流程-重点" aria-label="Permalink to &quot;3. 浏览器环境下的事件循环流程（重点！）&quot;">​</a></h4><p>按以下顺序循环执行，直到所有任务完成：</p><ol><li>执行「调用栈」中的所有同步代码（直到栈空）；</li><li>清空「微任务队列」：将微任务队列中的所有任务按顺序放入调用栈执行（<strong>一个都不留</strong>）；</li><li>执行一次「宏任务队列」中的第一个任务（注意：只执行一个！）；</li><li>执行完该宏任务后，再次清空「微任务队列」；</li><li>重复步骤 3-4，直到所有宏任务和微任务都执行完毕。</li></ol><h4 id="关键区别-浏览器-vs-node-环境" tabindex="-1">关键区别：浏览器 vs Node 环境 <a class="header-anchor" href="#关键区别-浏览器-vs-node-环境" aria-label="Permalink to &quot;关键区别：浏览器 vs Node 环境&quot;">​</a></h4><ul><li>Node 环境的事件循环有 6 个阶段（如 <code>timers</code>、<code>poll</code>、<code>check</code>），微任务在每个阶段结束后清空；</li><li>浏览器环境的事件循环更简单：宏任务执行 1 个 → 清空微任务 → 重复。</li></ul><h3 id="六、微任务与宏任务的区别-从本质到应用" tabindex="-1">六、微任务与宏任务的区别（从本质到应用） <a class="header-anchor" href="#六、微任务与宏任务的区别-从本质到应用" aria-label="Permalink to &quot;六、微任务与宏任务的区别（从本质到应用）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比维度</th><th>宏任务（MacroTask）</th><th>微任务（MicroTask）</th></tr></thead><tbody><tr><td>触发主体</td><td>浏览器/宿主环境（如 Chrome、Node）</td><td>JS 引擎自身（如 V8）</td></tr><tr><td>执行优先级</td><td>低（每个宏任务执行后，必须先清空微任务）</td><td>高（同步代码执行完后，立即清空所有微任务）</td></tr><tr><td>队列数量</td><td>多个（如定时器队列、DOM 事件队列、AJAX 队列）</td><td>一个（所有微任务共用一个队列，按顺序执行）</td></tr><tr><td>常见类型</td><td><code>script</code>、<code>setTimeout</code>、<code>setInterval</code>、DOM 事件、AJAX、<code>requestAnimationFrame</code></td><td><code>Promise.then/catch/finally</code>、<code>MutationObserver</code>、<code>queueMicrotask</code></td></tr><tr><td>设计目的</td><td>处理“耗时较长”或“需要宿主支持”的异步操作（如网络请求、定时器）</td><td>处理“短耗时”的异步回调（如 Promise 状态变更），保证数据一致性（避免多次渲染）</td></tr></tbody></table><h4 id="核心原理-为什么微任务优先级更高" tabindex="-1">核心原理：为什么微任务优先级更高？ <a class="header-anchor" href="#核心原理-为什么微任务优先级更高" aria-label="Permalink to &quot;核心原理：为什么微任务优先级更高？&quot;">​</a></h4><ul><li>微任务通常是“同步操作的后续回调”（如 Promise 执行完后的 <code>then</code>），需要尽快执行，避免数据状态不一致；</li><li>例如：如果微任务和宏任务优先级相同，<code>Promise.then</code> 的回调可能会被 <code>setTimeout</code> 回调阻塞，导致依赖 Promise 结果的代码出错。</li></ul><h4 id="应用场景" tabindex="-1">应用场景： <a class="header-anchor" href="#应用场景" aria-label="Permalink to &quot;应用场景：&quot;">​</a></h4><ul><li>微任务：需要“立即执行”的回调（如数据更新后刷新 UI、处理 Promise 结果）；</li><li>宏任务：需要“延迟执行”或“耗时”的操作（如定时器、网络请求、DOM 事件监听）。</li></ul><h3 id="七、学习-开发中用到的-ai-工具-前端场景化应用" tabindex="-1">七、学习/开发中用到的 AI 工具（前端场景化应用） <a class="header-anchor" href="#七、学习-开发中用到的-ai-工具-前端场景化应用" aria-label="Permalink to &quot;七、学习/开发中用到的 AI 工具（前端场景化应用）&quot;">​</a></h3><h4 id="_1-学习阶段-侧重-理解知识点" tabindex="-1">1. 学习阶段（侧重“理解知识点”） <a class="header-anchor" href="#_1-学习阶段-侧重-理解知识点" aria-label="Permalink to &quot;1. 学习阶段（侧重“理解知识点”）&quot;">​</a></h4><ul><li><strong>ChatGPT 4o/豆包/通义千问</strong>： <ul><li>用途：拆解复杂概念（如事件循环、闭包）、解释报错原因（如“Uncaught TypeError: Cannot read property &#39;xxx&#39; of undefined”）、对比技术选型（如 Vue3 vs React）；</li><li>示例：“用通俗的语言解释浏览器渲染中的重排和重绘，再举 3 个触发重排的例子”。</li></ul></li><li><strong>GitHub Copilot X</strong>： <ul><li>用途：看开源项目源码时，自动生成注释（理解核心逻辑）、解释陌生 API（如 <code>Intl.DateTimeFormat</code>）；</li></ul></li><li><strong>AI 题库工具（如 LeetCode AI 助手）</strong>： <ul><li>用途：刷算法题时，分析解题思路（如动态规划、贪心）、优化代码（如时间复杂度从 O(n²) 降到 O(n)）。</li></ul></li></ul><h4 id="_2-开发阶段-侧重-提高效率" tabindex="-1">2. 开发阶段（侧重“提高效率”） <a class="header-anchor" href="#_2-开发阶段-侧重-提高效率" aria-label="Permalink to &quot;2. 开发阶段（侧重“提高效率”）&quot;">​</a></h4><ul><li><strong>代码生成/补全</strong>： <ul><li>GitHub Copilot/Cursor：自动补全重复代码（如表单验证、axios 请求封装）、生成测试用例（如 Jest 测试代码）；</li><li>示例：“用 Vue3 + TypeScript 写一个带分页的表格组件，支持搜索、排序，包含类型定义”。</li></ul></li><li><strong>样式生成</strong>： <ul><li>Tailwind CSS AI：输入自然语言（如“一个圆角、阴影、hover 时放大的按钮，颜色为蓝色”），自动生成 Tailwind 类；</li><li>CSS Scan AI：上传设计图，自动生成 CSS 代码（适配响应式）。</li></ul></li><li><strong>错误排查/优化</strong>： <ul><li>Sentry AI：分析前端报错日志（如生产环境的白屏、卡顿），定位根因（如“内存泄漏源于未清除的定时器”）；</li><li>CodeLlama：优化代码性能（如将嵌套循环改为 map 遍历、减少 DOM 操作）。</li></ul></li><li><strong>文档生成</strong>： <ul><li>Documatic：根据代码自动生成 API 文档（如组件的 props、方法说明）；</li><li>AI 翻译工具（如 DeepL）：翻译英文技术文档（如 MDN、React 官网）。</li></ul></li></ul><h3 id="八、使用-ai-开发过程中遇到的问题-真实场景痛点" tabindex="-1">八、使用 AI 开发过程中遇到的问题（真实场景痛点） <a class="header-anchor" href="#八、使用-ai-开发过程中遇到的问题-真实场景痛点" aria-label="Permalink to &quot;八、使用 AI 开发过程中遇到的问题（真实场景痛点）&quot;">​</a></h3><ol><li><p><strong>代码有隐藏 Bug（边界条件缺失）</strong>：</p><ul><li>示例：AI 生成的“数组去重”代码，没考虑 <code>null</code>、<code>undefined</code> 或对象元素（如 <code>[1, 2, 2, null, null]</code> 去重后漏了 <code>null</code>）；</li><li>原因：AI 基于训练数据生成，可能忽略小众场景或边界条件。</li></ul></li><li><p><strong>代码不符合项目规范</strong>：</p><ul><li>示例：项目要求用 ESLint 规则（如 <code>no-var</code>、<code>indent: 2</code>），但 AI 生成的代码用了 <code>var</code>、4 空格缩进；</li><li>原因：AI 不知道项目的具体规范（如命名规范、目录结构）。</li></ul></li><li><p><strong>过度依赖导致能力退化</strong>：</p><ul><li>场景：基础语法（如 <code>reduce</code> 用法、闭包）长期靠 AI 生成，自己记不住核心逻辑，面试时卡壳；</li><li>风险：遇到 AI 无法解决的复杂问题（如框架源码调试），缺乏独立排查能力。</li></ul></li><li><p><strong>需求理解偏差</strong>：</p><ul><li>示例：要求“React 函数组件的防抖搜索”，AI 生成的是类组件代码，或防抖逻辑写反（<code>clearTimeout</code> 位置错误）；</li><li>原因：需求描述不清晰，或 AI 对技术栈的细节理解不足。</li></ul></li><li><p><strong>性能/安全性问题</strong>：</p><ul><li>性能：AI 生成的代码可能效率低（如用 <code>for</code> 循环遍历 DOM 多次，而非 <code>documentFragment</code>）；</li><li>安全：生成的 AJAX 请求没处理 XSS（如直接将用户输入拼接到 URL）、没验证接口返回数据。</li></ul></li><li><p><strong>技术选型过时</strong>：</p><ul><li>示例：生成的 Vue 代码用了 <code>Vue 2</code> 的 <code>Options API</code>，而项目用的是 Vue 3 的 <code>Composition API</code>；</li><li>原因：AI 训练数据有时间滞后，对最新技术（如 Vue 3.4 的新特性）支持不足。</li></ul></li></ol><h3 id="九、如何向-ai-提问-生成更好的代码-精准提问方法论" tabindex="-1">九、如何向 AI 提问，生成更好的代码？（精准提问方法论） <a class="header-anchor" href="#九、如何向-ai-提问-生成更好的代码-精准提问方法论" aria-label="Permalink to &quot;九、如何向 AI 提问，生成更好的代码？（精准提问方法论）&quot;">​</a></h3><p>核心原则：<strong>给 AI 足够的“上下文+约束+目标”</strong>，避免模糊描述，让 AI 知道“要做什么、不能做什么、达到什么效果”。</p><h4 id="_1-明确需求场景-含输入-输出" tabindex="-1">1. 明确需求场景（含输入/输出） <a class="header-anchor" href="#_1-明确需求场景-含输入-输出" aria-label="Permalink to &quot;1. 明确需求场景（含输入/输出）&quot;">​</a></h4><ul><li>反面示例：“写一个搜索组件”（太模糊，AI 不知道技术栈、功能、样式）；</li><li>正面示例：“React 18 函数组件，实现一个带防抖的搜索输入框：① 输入防抖 500ms；② 输入为空时不发送请求；③ 请求成功后展示结果列表（每一项包含标题和描述）；④ 请求失败时显示错误提示（用 Ant Design 的 Message 组件）”。</li></ul><h4 id="_2-提供约束条件-技术栈-规范-限制" tabindex="-1">2. 提供约束条件（技术栈/规范/限制） <a class="header-anchor" href="#_2-提供约束条件-技术栈-规范-限制" aria-label="Permalink to &quot;2. 提供约束条件（技术栈/规范/限制）&quot;">​</a></h4><ul><li>示例：“用 TypeScript 编写，兼容 ES6+，不使用第三方库（如 lodash），符合 Airbnb ESLint 规范，代码中添加关键逻辑注释”。</li></ul><h4 id="_3-给出参考示例-输入-输出-样式" tabindex="-1">3. 给出参考示例（输入/输出/样式） <a class="header-anchor" href="#_3-给出参考示例-输入-输出-样式" aria-label="Permalink to &quot;3. 给出参考示例（输入/输出/样式）&quot;">​</a></h4><ul><li>示例：“输入：用户输入‘前端面试’，输出：发送 GET 请求到 <code>/api/search?q=前端面试</code>，响应格式为 <code>{ code: 200, data: [{ title: &#39;...&#39;, desc: &#39;...&#39; }] }</code>，请按这个响应格式处理数据”。</li></ul><h4 id="_4-要求解释和优化方向" tabindex="-1">4. 要求解释和优化方向 <a class="header-anchor" href="#_4-要求解释和优化方向" aria-label="Permalink to &quot;4. 要求解释和优化方向&quot;">​</a></h4><ul><li>示例：“生成代码后，解释防抖逻辑的核心原理，再说明如何优化这个组件的性能（如缓存请求结果、避免重复渲染）”。</li></ul><h4 id="_5-逐步细化需求-迭代式提问" tabindex="-1">5. 逐步细化需求（迭代式提问） <a class="header-anchor" href="#_5-逐步细化需求-迭代式提问" aria-label="Permalink to &quot;5. 逐步细化需求（迭代式提问）&quot;">​</a></h4><p>如果第一次生成的代码不符合预期，<strong>精准补充细节</strong>，而非重新提问：</p><ul><li>补充示例：“刚才的代码没有处理请求中断（如用户快速输入时，取消上一次请求），请用 AbortController 实现请求中断，同时添加加载状态（用 Ant Design 的 Spin 组件）”。</li></ul><h4 id="_6-避免-开放式提问-多用-封闭式-细节" tabindex="-1">6. 避免“开放式提问”，多用“封闭式+细节” <a class="header-anchor" href="#_6-避免-开放式提问-多用-封闭式-细节" aria-label="Permalink to &quot;6. 避免“开放式提问”，多用“封闭式+细节”&quot;">​</a></h4><ul><li>反面示例：“这个组件怎么写更好？”；</li><li>正面示例：“这个搜索组件的防抖逻辑，有没有办法减少不必要的状态更新？请用 useCallback 和 useMemo 优化，并说明优化原因”。</li></ul><h3 id="十、了解哪些-ai-工具-前端分类梳理" tabindex="-1">十、了解哪些 AI 工具？（前端分类梳理） <a class="header-anchor" href="#十、了解哪些-ai-工具-前端分类梳理" aria-label="Permalink to &quot;十、了解哪些 AI 工具？（前端分类梳理）&quot;">​</a></h3><p>按“功能场景”分类，方便按需选择：</p><table tabindex="0"><thead><tr><th>功能分类</th><th>代表工具</th><th>核心用途</th></tr></thead><tbody><tr><td>通用问答/学习</td><td>ChatGPT 4o、豆包、通义千问、文心一言</td><td>技术咨询、概念解释、报错分析、技术选型对比</td></tr><tr><td>代码生成/补全</td><td>GitHub Copilot、Cursor、CodeLlama</td><td>代码补全、组件生成、测试用例编写、开源项目源码解释</td></tr><tr><td>样式/UI 生成</td><td>Tailwind CSS AI、CSS Scan AI、MidJourney</td><td>生成 CSS 代码、设计图转 UI 组件、响应式布局适配</td></tr><tr><td>错误排查/性能优化</td><td>Sentry AI、LogRocket AI、CodeGeeX</td><td>生产环境报错定位、内存泄漏分析、代码性能优化（时间/空间复杂度）</td></tr><tr><td>文档/注释生成</td><td>Documatic、CodeWhisperer、AI Code Commenter</td><td>自动生成 API 文档、代码注释、技术文档翻译（英文→中文）</td></tr><tr><td>低代码/可视化</td><td>Webflow AI、Mendix AI、AppMaster</td><td>拖拽式开发中生成组件逻辑、适配多端（PC/移动端）、自动生成部署配置</td></tr><tr><td>算法辅助</td><td>LeetCode AI 助手、ChatGPT Code Interpreter</td><td>算法思路分析、代码调试、复杂度优化、生成测试数据</td></tr></tbody></table><h4 id="关键选型建议" tabindex="-1">关键选型建议： <a class="header-anchor" href="#关键选型建议" aria-label="Permalink to &quot;关键选型建议：&quot;">​</a></h4><ul><li>学习/咨询：优先 ChatGPT 4o（逻辑清晰）、豆包（中文支持好）；</li><li>开发/补全：优先 GitHub Copilot（与 VS Code 集成，适配前端技术栈）；</li><li>样式生成：优先 Tailwind CSS AI（与 Tailwind 生态无缝衔接）；</li><li>错误排查：优先 Sentry AI（与前端监控工具集成，适合生产环境）。</li></ul><h3 id="十一、ai-越聊越错的原因-从-ai-工作原理拆解" tabindex="-1">十一、AI 越聊越错的原因（从 AI 工作原理拆解） <a class="header-anchor" href="#十一、ai-越聊越错的原因-从-ai-工作原理拆解" aria-label="Permalink to &quot;十一、AI 越聊越错的原因（从 AI 工作原理拆解）&quot;">​</a></h3><p>AI 不是“理解”内容，而是基于 <strong>训练数据的统计概率</strong> 生成连贯的回答，越聊越错的核心原因是「上下文失真+错误累积」：</p><ol><li><p><strong>上下文窗口限制（最核心原因）</strong>：</p><ul><li>AI 有“最大上下文长度”（如 GPT-4o 是 128k tokens，约 10 万字），聊得越多，早期的关键信息（如需求、约束、技术栈）会被“遗忘”（超出窗口的信息无法访问）；</li><li>示例：第一次提问时要求“用 Vue3”，聊了 20 轮后，AI 可能忘记，生成 Vue2 代码。</li></ul></li><li><p><strong>错误累积效应（蝴蝶效应）</strong>：</p><ul><li>第一次生成的代码有小错误（如变量名写错），如果没被精准纠正，AI 会把这个错误当成“正确前提”，后续基于错误推导，导致错上加错；</li><li>示例：AI 第一次把 <code>clearTimeout(timer)</code> 写成 <code>timer = null</code>（防抖逻辑错误），后续聊“优化防抖”时，会基于 <code>timer = null</code> 继续修改，越改越错。</li></ul></li><li><p><strong>模糊的纠错反馈</strong>：</p><ul><li>如果用户只说“不对”“有问题”，AI 无法定位错误点（是语法错？逻辑错？不符合规范？），只能“猜测修改”，可能改对一个地方，又错另一个；</li><li>反例：“你生成的防抖函数没清除定时器，导致多次触发请求”（精准指出错误点）。</li></ul></li><li><p><strong>AI 的“迎合性”倾向</strong>：</p><ul><li>AI 的训练目标是“生成连贯、符合用户预期的回答”，而非“保证正确性”；</li><li>如果用户在对话中表现出“误解”（如误以为 <code>setTimeout</code> 是微任务），AI 可能顺着用户的误解继续生成内容，而非纠正。</li></ul></li><li><p><strong>缺乏实时校验能力</strong>：</p><ul><li>AI 生成代码时不会实际运行，无法发现运行时错误（如边界条件、异步时序问题）；</li><li>聊得越多，代码逻辑越复杂，AI 越难预判运行时结果，错误率越高。</li></ul></li></ol><h3 id="十二、为什么难以纠错-越聊越正确-为什么越聊幻觉越大" tabindex="-1">十二、为什么难以纠错（越聊越正确）？为什么越聊幻觉越大？ <a class="header-anchor" href="#十二、为什么难以纠错-越聊越正确-为什么越聊幻觉越大" aria-label="Permalink to &quot;十二、为什么难以纠错（越聊越正确）？为什么越聊幻觉越大？&quot;">​</a></h3><h4 id="_1-为什么难以纠错-做到-越聊越正确" tabindex="-1">1. 为什么难以纠错，做到“越聊越正确”？ <a class="header-anchor" href="#_1-为什么难以纠错-做到-越聊越正确" aria-label="Permalink to &quot;1. 为什么难以纠错，做到“越聊越正确”？&quot;">​</a></h4><p>核心是「纠错成本远高于初始生成」，需要满足两个前提，而实际中很难做到：</p><ul><li>前提 1：用户必须 <strong>精准理解错误原因</strong>（如“防抖函数的定时器清除逻辑错误，因为 <code>clearTimeout</code> 应该在每次输入时调用，而不是在回调中”）；</li><li>前提 2：用户必须 <strong>用 AI 能理解的语言描述错误</strong>（避免模糊反馈）；</li><li>现实问题： <ul><li>用户可能自己也没完全搞懂错误原因（比如只知道代码不生效，但不知道为什么）；</li><li>即使精准反馈，AI 可能因上下文窗口限制，忘记之前的约束（如“之前要求兼容 ES6，现在纠正时又用了 ES7 语法”）。</li></ul></li></ul><h4 id="_2-为什么越聊幻觉越大-幻觉-ai-编造不存在的信息" tabindex="-1">2. 为什么越聊幻觉越大？（幻觉=AI 编造不存在的信息） <a class="header-anchor" href="#_2-为什么越聊幻觉越大-幻觉-ai-编造不存在的信息" aria-label="Permalink to &quot;2. 为什么越聊幻觉越大？（幻觉=AI 编造不存在的信息）&quot;">​</a></h4><p>AI 的“幻觉”本质是「基于统计概率的“合理编造”」，聊得越多，幻觉越严重的原因：</p><ul><li><p>（1）<strong>信息缺口扩大</strong>：</p><ul><li>对话深入后，涉及的细节越来越多（如“这个组件的 props 类型定义、生命周期钩子、与父组件的通信方式”），AI 的训练数据中可能没有对应的“完整信息”；</li><li>为了生成“连贯的回答”，AI 会基于类似场景“编造”信息（如编造一个不存在的 Vue3 钩子函数、一个不符合规范的 props 类型）。</li></ul></li><li><p>（2）<strong>上下文溢出导致“脑补”</strong>：</p><ul><li>超出上下文窗口后，AI 无法访问早期关键信息，只能基于剩余的碎片化信息“脑补”逻辑；</li><li>示例：早期要求“用 axios 发请求”，聊到第 30 轮，AI 忘记，编造“用 <code>vue-request</code> 库（实际项目没引入），调用 <code>useRequest</code> 方法”。</li></ul></li><li><p>（3）<strong>训练数据的“模糊边界”</strong>：</p><ul><li>AI 对“正确信息”和“错误信息”的判断，基于训练数据中的“出现频率”，而非“事实正确性”；</li><li>比如小众技术（如某冷门框架的 API）在训练数据中出现次数少，AI 无法区分“正确 API”和“类似 API”，容易编造。</li></ul></li><li><p>（4）<strong>无反馈时的“自我强化”</strong>：</p><ul><li>如果用户没及时纠正第一次的幻觉，AI 会认为“这个编造的信息是正确的”，后续对话中反复使用，幻觉越来越严重；</li><li>示例：AI 第一次编造“Vue3 的 <code>onMountedAsync</code> 钩子（实际不存在）”，用户没纠正，后续聊组件生命周期时，会继续用这个钩子，甚至编造其用法。</li></ul></li></ul><h3 id="总结-1" tabindex="-1">总结 <a class="header-anchor" href="#总结-1" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>以上问题覆盖了前端核心基础（浏览器原理、事件循环、线程模型）和工程实践（AI 工具使用），都是字节二面关注的“深度理解”类知识点。学习时重点抓「原理+实例」：</p><ul><li>基础部分：用“流程拆解”（如渲染流程、事件循环流程）理解逻辑，用“实例验证”（如代码示例）巩固记忆；</li><li>AI 部分：结合实际开发场景，明确“AI 是工具，不是替代”，重点学习“如何高效利用 AI，同时避免依赖”。</li></ul><p>如果某个知识点想进一步深入（如 V8 引擎的事件循环实现、Web Worker 的通信原理），可以随时补充提问！</p><h2 id="_5-复盘反思" tabindex="-1">5 复盘反思 <a class="header-anchor" href="#_5-复盘反思" aria-label="Permalink to &quot;5 复盘反思&quot;">​</a></h2><p>今天二面的效果整体不错，问题出在最后的diff算法，以及人工智能，对于学过的知识已经快遗忘的，我认为说学过，面试官就会追问，反而面试效果不佳，所以学过但是忘了就等于没学就行了。</p><p>二面已通过，明天HR面，应该是最后一次了。</p><p>另外在思考过程中，眼睛不要向上瞟。 面试官这次提供了一个有趣的说法，日常实习不保证100%的转正机会。</p><p>一面考基础，二面深挖项目，太深了太细致了太吓人了，这项目但凡不是自己写的，肯定完蛋（我是自己一个字母一个字母敲上去的😋）</p><p>而且这几天的面试官都针对如何使用AI，以及AI相关的内容进行了提问，学习AI十分重要，读研是必要的。</p><h1 id="字节跳动-字节云-豆包前端实习-hr面" tabindex="-1">字节跳动-字节云-豆包前端实习-HR面 <a class="header-anchor" href="#字节跳动-字节云-豆包前端实习-hr面" aria-label="Permalink to &quot;字节跳动-字节云-豆包前端实习-HR面&quot;">​</a></h1><p>时间 11/28/25 时长 30min</p><h2 id="_1-内容-1" tabindex="-1">1 内容 <a class="header-anchor" href="#_1-内容-1" aria-label="Permalink to &quot;1 内容&quot;">​</a></h2><p>这次忘了录制视频了</p><ul><li>自我介绍</li><li>提问</li></ul><h2 id="_2-提问" tabindex="-1">2 提问 <a class="header-anchor" href="#_2-提问" aria-label="Permalink to &quot;2 提问&quot;">​</a></h2><p>大概就是问问理想，你能给企业带来什么价值，诸如此类...</p><ul><li>你的优缺点</li><li>你的项目，难点</li><li>平时用什么AI</li><li>是否保研？</li><li>你在带队的过程中所负责的任务，以及最后的成果呢</li></ul><h2 id="_3-复盘反思-1" tabindex="-1">3 复盘反思 <a class="header-anchor" href="#_3-复盘反思-1" aria-label="Permalink to &quot;3 复盘反思&quot;">​</a></h2><blockquote><p>首先，我认为让一个不懂技术的人来面试我们这些程序员并且还是最后一面，就很有无力感，你没法和她说技术，只能说他能听得懂的。他还觉得你的项目不难啊，我不太满意哈。还觉得我没有实习经历，不懂企业开发的流程，那TM谁一开始就是有经验的，哦都有经验了，谁还投实习，姐们。那你就别一开始找我啊，我简历上不是没写经历吗，那肯定就没有啊，你还来找我干什么。而且，她还迟到了，你是HR，你还迟到</p></blockquote><blockquote><p>反正本身我也要去读研，对于读研，实习也不是必要的，你要是喜欢，那就去找你的985吧，我211伺候不了，也不想伺候。我准备学后端了，嘿嘿。</p></blockquote><p>感觉完蛋，真的。感觉自己表现的并不好，没有将自己的全部优势展现出来。</p><p>磐松也没有消息，都2天了... 字节的HR面似乎对我也不太满意，这不是又要重新投递啊...</p><p>据别人的面经说</p><blockquote><p>三面结束以后等hr联系，等了很多天都没有等到，3月4日的时候已经心灰意冷，开始准备其他公司的校招了，没想到第二天hr联系我了，超兴奋</p></blockquote><p>可能，就是这样不给你消息的，让你着急。</p>',194)])])}const b=e(a,[["render",r]]);export{p as __pageData,b as default};
